"use strict";(globalThis.webpackChunkarbor_vote_docs=globalThis.webpackChunkarbor_vote_docs||[]).push([[258],{2253(e){e.exports=JSON.parse('{"archive":{"blogPosts":[{"id":"welcome","metadata":{"permalink":"/docs/blog/welcome","source":"@site/blog/2020-07-01-welcome.md","title":"Welcome","description":"Welcome to the deliberate project!","date":"2020-07-01T00:00:00.000Z","tags":[{"inline":true,"label":"Democracy","permalink":"/docs/blog/tags/democracy"},{"inline":true,"label":"Rationalism","permalink":"/docs/blog/tags/rationalism"}],"readingTime":0.41,"hasTruncateMarker":false,"authors":[{"name":"Michael","title":"Founder","url":"https://github.com/heueristik","imageURL":"https://avatars1.githubusercontent.com/u/20623991?s=400&v=4","key":"michael","page":null}],"frontMatter":{"slug":"welcome","title":"Welcome","authors":["michael"],"tags":["Democracy","Rationalism"]},"unlisted":false},"content":"Welcome to the deliberate project!\\n\\nThe project started at the ETHLondon Hackathon in March 2020. \\nThe idea was to build decentralized debate platform for \\nrational decision-making  based on quadratic voting in a tree of pro and con arguments.\\nThis form of democratic decision making is known under the term \\n[deliberative democracy](https://en.wikipedia.org/wiki/Deliberative_democracy).\\n\\nWith the global challenges ahead, this is something the world needs right now. \ud83c\udf0d<br/>\\nSo let\'s be constructive and build a decentralized and democratic future together!"}]}}')}}]);